internal inline fun Path.commonRelativeTo(other: Path): Path {
  require(root == other.root) {
    "Paths of different roots cannot be relative to each other: $this and $other"
  }

  val thisSegments = this.segmentsBytes
  val otherSegments = other.segmentsBytes

  // We look at the path both have in common.
  var firstNewSegmentIndex = 0
  val minSegmentsSize = minOf(thisSegments.size, otherSegments.size)
  while (firstNewSegmentIndex < minSegmentsSize &&
    thisSegments[firstNewSegmentIndex] == otherSegments[firstNewSegmentIndex]
  ) {
    firstNewSegmentIndex++
  }

  if (firstNewSegmentIndex == minSegmentsSize && bytes.size == other.bytes.size) {
    // `this` and `other` are the same path.
    return ".".toPath()
  }

  require(otherSegments.subList(firstNewSegmentIndex, otherSegments.size).indexOf(DOT_DOT) == -1) {
    "Impossible relative path to resolve: $this and $other"
  }

  if (other.bytes == DOT) {
    // Anything relative to "." is itself!
    return this
  }

  val buffer = Buffer()
  val slash = other.slash ?: slash ?: Path.DIRECTORY_SEPARATOR.toSlash()
  for (i in firstNewSegmentIndex until otherSegments.size) {
    buffer.write(DOT_DOT)
    buffer.write(slash)
  }
  for (i in firstNewSegmentIndex until thisSegments.size) {
    buffer.write(thisSegments[i])
    buffer.write(slash)
  }
  return buffer.toPath(normalize = false)
}

abstract class SuspendingTransacterImpl(driver: SqlDriver) :
  BaseTransacterImpl(driver),
  SuspendingTransacter {
  override suspend fun <R> transactionWithResult(
    noEnclosing: Boolean,
    bodyWithReturn: suspend SuspendingTransactionWithReturn<R>.() -> R,
  ): R {
    return when (driver) {
      is SuspendingTransacter.TransactionDispatcher -> driver.dispatch {
        transactionWithWrapper(noEnclosing, bodyWithReturn)
      }

      else -> transactionWithWrapper(noEnclosing, bodyWithReturn)
    }
  }

  override suspend fun transaction(
    noEnclosing: Boolean,
    body: suspend SuspendingTransactionWithoutReturn.() -> Unit,
  ) {
    return when (driver) {
      is SuspendingTransacter.TransactionDispatcher -> driver.dispatch {
        transactionWithWrapper(noEnclosing, body)
      }

      else -> transactionWithWrapper(noEnclosing, body)
    }
  }

  private suspend fun <R> transactionWithWrapper(noEnclosing: Boolean, wrapperBody: suspend SuspendingTransactionWrapper<R>.() -> R): R {
    val transaction = driver.newTransaction().await()
    val enclosing = transaction.enclosingTransaction()

    check(enclosing == null || !noEnclosing) { "Already in a transaction" }

    var thrownException: Throwable? = null
    var returnValue: R? = null

    try {
      transaction.transacter = this
      returnValue = SuspendingTransactionWrapper<R>(transaction).wrapperBody()
      transaction.successful = true
    } catch (e: Throwable) {
      thrownException = e
    } finally {
      transaction.endTransaction().await()
      return postTransactionCleanup(transaction, enclosing, thrownException, returnValue)
    }
  }
}

sealed class ConnectionWrapper : SqlDriver {
  internal abstract fun <R> accessConnection(
    readOnly: Boolean,
    block: ThreadConnection.() -> R,
  ): R

  private fun <R> accessStatement(
    readOnly: Boolean,
    identifier: Int?,
    sql: String,
    binders: (SqlPreparedStatement.() -> Unit)?,
    block: (Statement) -> R,
  ): R {
    return accessConnection(readOnly) {
      val statement = useStatement(identifier, sql)
      try {
        if (binders != null) {
          SqliterStatement(statement).binders()
        }

        block(statement)
      } finally {
        statement.resetStatement()
        clearIfNeeded(identifier, statement)
      }
    }
  }

  final override fun execute(
    identifier: Int?,
    sql: String,
    parameters: Int,
    binders: (SqlPreparedStatement.() -> Unit)?,
  ): QueryResult<Long> = QueryResult.Value(
    accessStatement(false, identifier, sql, binders) { statement ->
      statement.executeUpdateDelete().toLong()
    },
  )

  final override fun <R> executeQuery(
    identifier: Int?,
    sql: String,
    mapper: (SqlCursor) -> QueryResult<R>,
    parameters: Int,
    binders: (SqlPreparedStatement.() -> Unit)?,
  ): QueryResult<R> {
    val checkSqlStatement = sql.trimStart().uppercase()
    val useReadOnly = !(
      checkSqlStatement.startsWith("UPDATE") ||
        checkSqlStatement.startsWith("INSERT") ||
        checkSqlStatement.startsWith("DELETE")
      )

    return accessStatement(useReadOnly, identifier, sql, binders) { statement ->
      mapper(SqliterSqlCursor(statement.query()))
    }
  }
}

private class AndroidQuery(
  override val sql: String,
  private val database: SupportSQLiteDatabase,
  override val argCount: Int,
  private val windowSizeBytes: Long?,
) : SupportSQLiteQuery,
  AndroidStatement {
  private val binds = MutableList<((SupportSQLiteProgram) -> Unit)?>(argCount) { null }

  override fun bindBytes(index: Int, bytes: ByteArray?) {
    binds[index] = { if (bytes == null) it.bindNull(index + 1) else it.bindBlob(index + 1, bytes) }
  }

  override fun bindLong(index: Int, long: Long?) {
    binds[index] = { if (long == null) it.bindNull(index + 1) else it.bindLong(index + 1, long) }
  }

  override fun bindDouble(index: Int, double: Double?) {
    binds[index] = { if (double == null) it.bindNull(index + 1) else it.bindDouble(index + 1, double) }
  }

  override fun bindString(index: Int, string: String?) {
    binds[index] = { if (string == null) it.bindNull(index + 1) else it.bindString(index + 1, string) }
  }

  override fun bindBoolean(index: Int, boolean: Boolean?) {
    binds[index] = {
      if (boolean == null) {
        it.bindNull(index + 1)
      } else {
        it.bindLong(index + 1, if (boolean) 1L else 0L)
      }
    }
  }

  override fun execute() = throw UnsupportedOperationException()

  override fun <R> executeQuery(mapper: (SqlCursor) -> QueryResult<R>): R {
    return database.query(this)
      .use { cursor -> mapper(AndroidCursor(cursor, windowSizeBytes)).value }
  }

  override fun bindTo(statement: SupportSQLiteProgram) {
    for (action in binds) {
      action!!(statement)
    }
  }

  override fun toString() = sql

  override fun close() {}
}

override fun addListener(vararg queryKeys: String, listener: Query.Listener) {
  lock.withLock {
    queryKeys.forEach {
      listeners.getOrPut(it) { mutableSetOf() }.add(listener)
    }
  }
}

override fun removeListener(vararg queryKeys: String, listener: Query.Listener) {
  lock.withLock {
    queryKeys.forEach {
      listeners.get(it)?.remove(listener)
    }
  }
}

override fun notifyListeners(vararg queryKeys: String) {
  val listenersToNotify = mutableSetOf<Query.Listener>()
  lock.withLock {
    queryKeys.forEach { key -> listeners.get(key)?.let { listenersToNotify.addAll(it) } }
  }
  listenersToNotify.forEach(Query.Listener::queryResultsChanged)
}

override fun currentTransaction(): Transacter.Transaction? {
  return borrowedConnectionThread.get()?.value?.transaction?.value
}

override fun newTransaction(): QueryResult<Transacter.Transaction> {
  val alreadyBorrowed = borrowedConnectionThread.get()
  val transaction = if (alreadyBorrowed == null) {
    val borrowed = transactionPool.borrowEntry()

    try {
      val trans = borrowed.value.newTransaction()

      borrowedConnectionThread.value = borrowed
      trans
    } catch (e: Throwable) {
      // Unlock on failure.
      borrowed.release()
      throw e
    }
  } else {
    alreadyBorrowed.value.newTransaction()
  }

  return QueryResult.Value(transaction)
}

override fun encodeElement(descriptor: SerialDescriptor, index: Int): Boolean {
    when (mode) {
        WriteMode.LIST -> {
            if (!composer.writingFirst)
                composer.print(COMMA)
            composer.nextItem()
        }
        WriteMode.MAP -> {
            if (!composer.writingFirst) {
                forceQuoting = if (index % 2 == 0) {
                    composer.print(COMMA)
                    composer.nextItem() // indent should only be put after commas in map
                    true
                } else {
                    composer.print(COLON)
                    composer.space()
                    false
                }
            } else {
                forceQuoting = true
                composer.nextItem()
            }
        }
        WriteMode.POLY_OBJ -> {
            if (index == 0)
                forceQuoting = true
            if (index == 1) {
                composer.print(COMMA)
                composer.space()
                forceQuoting = false
            }
        }
        else -> {
            if (!composer.writingFirst)
                composer.print(COMMA)
            composer.nextItem()
            encodeString(descriptor.getJsonElementName(json, index))
            composer.print(COLON)
            composer.space()
        }
    }
    return true
}

package io.mockk.impl.verify

import io.mockk.MockKGateway
import io.mockk.MockKGateway.VerificationParameters
import io.mockk.MockKGateway.VerificationResult
import io.mockk.RecordedCall
import io.mockk.impl.log.SafeToString
import io.mockk.impl.stub.StubRepository
import io.mockk.impl.verify.VerificationHelpers.allInvocations
import io.mockk.impl.verify.VerificationHelpers.reportCalls

class OrderedCallVerifier(
    val stubRepo: StubRepository,
    val safeToString: SafeToString,
) : MockKGateway.CallVerifier {
    private val captureBlocks = mutableListOf<() -> Unit>()

    override fun verify(
        verificationSequence: List<RecordedCall>,
        params: VerificationParameters,
    ): VerificationResult {
        val allCalls = verificationSequence.allInvocations(stubRepo)

        if (verificationSequence.size > allCalls.size) {
            return VerificationResult.Failure(
                safeToString.exec {
                    "fewer calls happened than demanded by order verification sequence. " +
                        reportCalls(verificationSequence, allCalls)
                },
            )
        }

        val lcs = LCSMatchingAlgo(allCalls, verificationSequence, captureBlocks)

        return if (lcs.lcs()) {
            VerificationResult.OK(lcs.verifiedCalls)
        } else {
            VerificationResult.Failure(
                safeToString.exec {
                    "calls are not in verification order" + reportCalls(verificationSequence, allCalls, lcs)
                },
            )
        }
    }

    override fun captureArguments() = captureBlocks.forEach { it() }
}

